gory:kk]][[Category:kk]][[Category:dd]][[Category:kk]][[Category:Ōmi Ōtsu Palace]][[Category:kk]][[Category:dd]][[Category:kk]][[Category:kk]][[Category:dd]][[Category:kk]][[Category:pgoodbye $1]][[Category:new pages]][[Category:kk]][[Category:{Ōmi Ōtsu Palace]][[Category:kk]][[Category:dd]][[Category:kk]][[Category:pgoodbye $1]][[Category:new pages]] [[Category:kk]]
